### Step 7.4 — Create the Electron main process

Create `electron/main.js`:

```js
const { app, BrowserWindow, ipcMain, dialog, shell } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const fs = require('fs');
const isDev = require('electron-is-dev');

let mainWindow;

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    minWidth: 900,
    minHeight: 600,
    frame: false,         // Custom titlebar
    titleBarStyle: 'hiddenInset',
    backgroundColor: '#0a0a0f',
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
      preload: path.join(__dirname, 'preload.js'),
    },
    icon: path.join(__dirname, 'assets', 'icon.png'),
  });

  mainWindow.loadURL(
    isDev
      ? 'http://localhost:5173'
      : `file://${path.join(__dirname, '../dist/index.html')}`
  );

  if (isDev) mainWindow.webContents.openDevTools({ mode: 'detach' });
}

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});

// ── IPC: Open folder dialog ──────────────────────────────────────────────────
ipcMain.handle('dialog:openFolder', async () => {
  const result = await dialog.showOpenDialog(mainWindow, {
    properties: ['openDirectory'],
    title: 'Select Your Project Folder',
  });
  if (result.canceled) return null;
  return result.filePaths[0];
});

// ── IPC: Scan project folder (read-only) ─────────────────────────────────────
ipcMain.handle('project:scan', async (event, folderPath) => {
  const result = {
    folderPath,
    files: [],
    requirementsFile: null,
    entryPoint: null,
    projectType: null,
    packageManager: null,
  };

  // Recursive file scanner (depth-limited, read-only)
  function scanDir(dir, depth = 0) {
    if (depth > 4) return;
    try {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        if (entry.name.startsWith('.') || entry.name === 'node_modules' ||
            entry.name === '__pycache__' || entry.name === 'venv' ||
            entry.name === '.venv' || entry.name === 'dist' ||
            entry.name === 'build') continue;

        const fullPath = path.join(dir, entry.name);
        const relPath = path.relative(folderPath, fullPath);

        if (entry.isFile()) {
          result.files.push(relPath);

          // Detect requirements
          if (entry.name === 'requirements.txt') result.requirementsFile = relPath;
          if (entry.name === 'pyproject.toml' && !result.requirementsFile) result.requirementsFile = relPath;
          if (entry.name === 'package.json' && depth === 0) {
            result.requirementsFile = relPath;
            result.packageManager = 'npm';
          }

          // Detect entry point
          const entryPriority = ['main.py','app.py','run.py','server.py',
                                  'manage.py','index.js','server.js','app.js','main.js'];
          for (const ep of entryPriority) {
            if (entry.name === ep && !result.entryPoint) {
              result.entryPoint = relPath;
              result.projectType = ep.endsWith('.py') ? 'python' : 'node';
            }
          }
        } else if (entry.isDirectory()) {
          scanDir(fullPath, depth + 1);
        }
      }
    } catch (e) { /* skip permission errors */ }
  }

  scanDir(folderPath);
  return result;
});

// ── IPC: Run command with streaming output ────────────────────────────────────
ipcMain.handle('command:run', async (event, { command, args, cwd }) => {
  return new Promise((resolve) => {
    const proc = spawn(command, args, {
      cwd,
      shell: true,
      env: { ...process.env },
    });

    proc.stdout.on('data', (data) => {
      mainWindow.webContents.send('command:output', {
        type: 'stdout',
        text: data.toString(),
      });
    });

    proc.stderr.on('data', (data) => {
      mainWindow.webContents.send('command:output', {
        type: 'stderr',
        text: data.toString(),
      });
    });

    proc.on('close', (code) => {
      mainWindow.webContents.send('command:output', {
        type: 'exit',
        code,
        text: `\n[Process exited with code ${code}]\n`,
      });
      resolve({ code });
    });
  });
});

// ── IPC: Window controls ─────────────────────────────────────────────────────
ipcMain.on('window:minimize', () => mainWindow.minimize());
ipcMain.on('window:maximize', () => {
  mainWindow.isMaximized() ? mainWindow.unmaximize() : mainWindow.maximize();
});
ipcMain.on('window:close', () => mainWindow.close());
```

### Step 7.5 — Create the preload bridge

Create `electron/preload.js`:

```js
const { contextBridge, ipcRenderer } = require('electron');

contextBridge.exposeInMainWorld('electronAPI', {
  // Folder picker
  openFolder: () => ipcRenderer.invoke('dialog:openFolder'),

  // Project scanning
  scanProject: (folderPath) => ipcRenderer.invoke('project:scan', folderPath),

  // Command runner
  runCommand: (opts) => ipcRenderer.invoke('command:run', opts),

  // Stream listener
  onCommandOutput: (cb) => ipcRenderer.on('command:output', (_, data) => cb(data)),
  removeCommandListeners: () => ipcRenderer.removeAllListeners('command:output'),

  // Window controls
  minimizeWindow: () => ipcRenderer.send('window:minimize'),
  maximizeWindow: () => ipcRenderer.send('window:maximize'),
  closeWindow: () => ipcRenderer.send('window:close'),
});
```

