import { useState } from 'react';
import { motion } from 'framer-motion';
import { FolderOpen, FolderCheck } from 'lucide-react';

export default function ProjectDropzone({ onFolderSelect, onFolderDrop, projectPath }) {
  const [isDragging, setIsDragging] = useState(false);

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragging(false);
    const items = Array.from(e.dataTransfer.items);
    for (const item of items) {
      const entry = item.webkitGetAsEntry?.();
      if (entry?.isDirectory) {
        // Get path from file
        const file = item.getAsFile();
        if (file?.path) onFolderDrop(file.path);
        return;
      }
    }
    const files = Array.from(e.dataTransfer.files);
    if (files[0]?.path) onFolderDrop(files[0].path);
  };

  return (
    <motion.button
      onClick={onFolderSelect}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={handleDrop}
      whileHover={{ scale: 1.01 }}
      whileTap={{ scale: 0.99 }}
      className={`
        w-full rounded-lg border-2 border-dashed p-6 text-center
        transition-all duration-200 cursor-pointer
        ${isDragging
          ? 'border-accent bg-accent/10 shadow-[0_0_20px_rgba(0,212,255,0.2)]'
          : projectPath
            ? 'border-success/50 bg-success/5'
            : 'border-border hover:border-accent/50 hover:bg-panel'
        }
      `}
    >
      {projectPath ? (
        <>
          <FolderCheck className="w-8 h-8 text-success mx-auto mb-2" />
          <p className="text-success text-xs font-mono truncate">
            {projectPath.split(/[\\/]/).pop()}
          </p>
          <p className="text-muted text-xs mt-1">Click to change</p>
        </>
      ) : (
        <>
          <FolderOpen className="w-8 h-8 text-muted mx-auto mb-2" />
          <p className="text-text text-sm font-medium">Drop project folder</p>
          <p className="text-muted text-xs mt-1">or click to browse</p>
        </>
      )}
    </motion.button>
  );
}
