@tailwind utilities;

/* Drag region for custom titlebar */
.drag-region { -webkit-app-region: drag; }
.no-drag { -webkit-app-region: no-drag; }

/* Scrollbar */
::-webkit-scrollbar { width: 4px; height: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: #2a2a3a; border-radius: 2px; }
::-webkit-scrollbar-thumb:hover { background: #444460; }

/* Terminal text selection */
.terminal-text ::selection { background: rgba(0,212,255,0.3); }

/* Subtle CRT effect on terminal */
.terminal-crt::after {
  content: '';
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    rgba(0,0,0,0.03) 2px,
    rgba(0,0,0,0.03) 4px
  );
  pointer-events: none;
}

/* Glowing border on focus */
.glow-accent:focus-within {
  box-shadow: 0 0 0 1px rgba(0,212,255,0.5), 0 0 16px rgba(0,212,255,0.1);
}

/* Animated gradient background for scan state */
@keyframes gradientShift {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.scanning-gradient {
  background: linear-gradient(270deg, #0a0a0f, #0d1520, #0a0a0f);
  background-size: 200% 200%;
  animation: gradientShift 3s ease infinite;
}

