import { useState, useRef, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import TitleBar from './components/TitleBar';
import ProjectDropzone from './components/ProjectDropzone';
import ProjectInfo from './components/ProjectInfo';
import Terminal from './components/Terminal';
import ActionButtons from './components/ActionButtons';
import AIScanner from './components/AIScanner';

export default function App() {
  const [projectPath, setProjectPath] = useState(null);
  const [scanData, setScanData] = useState(null);
  const [aiAnalysis, setAiAnalysis] = useState(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isRunning, setIsRunning] = useState(false);
  const [terminalLines, setTerminalLines] = useState([
    { type: 'info', text: 'ProjectLauncher ready. Select a project folder to begin.\n' }
  ]);
  const [recentProjects, setRecentProjects] = useState(() => {
    try { return JSON.parse(localStorage.getItem('recentProjects') || '[]'); }
    catch { return []; }
  });

  const addTerminalLine = useCallback((line) => {
    setTerminalLines(prev => [...prev.slice(-500), line]);
  }, []);

  const handleFolderSelect = async () => {
    const folder = await window.electronAPI.openFolder();
    if (!folder) return;
    loadProject(folder);
  };

  const loadProject = async (folder) => {
    setProjectPath(folder);
    setScanData(null);
    setAiAnalysis(null);
    setTerminalLines([]);

    addTerminalLine({ type: 'info', text: `Loading project: ${folder}\n` });
    setIsScanning(true);

    const scan = await window.electronAPI.scanProject(folder);
    setScanData(scan);

    addTerminalLine({
      type: 'success',
      text: `Found ${scan.files.length} files | Entry: ${scan.entryPoint || 'detecting...'} | Requirements: ${scan.requirementsFile || 'none found'}\n`
    });

    const updated = [folder, ...recentProjects.filter(p => p !== folder)].slice(0, 10);
    setRecentProjects(updated);
    localStorage.setItem('recentProjects', JSON.stringify(updated));
  };

  return (
    <div className="h-screen w-screen bg-void text-text font-display flex flex-col overflow-hidden">
      <TitleBar />

      <div className="flex flex-1 overflow-hidden">
        <div className="w-80 flex flex-col border-r border-border bg-surface p-4 gap-4 overflow-y-auto">
          <ProjectDropzone
            onFolderSelect={handleFolderSelect}
            onFolderDrop={loadProject}
            projectPath={projectPath}
          />

          {recentProjects.length > 0 && (
            <div>
              <p className="text-xs text-muted uppercase tracking-widest mb-2">Recent Projects</p>
              {recentProjects.map(p => (
                <button
                  key={p}
                  onClick={() => loadProject(p)}
                  className="w-full text-left text-xs text-muted hover:text-accent truncate py-1 px-2 rounded hover:bg-panel transition-colors"
                  title={p}
                >
                  {p.split(/[\\/]/).pop()}
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="flex-1 flex flex-col overflow-hidden">
          <AnimatePresence mode="wait">
            {scanData ? (
              <motion.div
                key="content"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex-1 flex flex-col overflow-hidden"
              >
                <ProjectInfo scanData={scanData} aiAnalysis={aiAnalysis} />
                <AIScanner
                  scanData={scanData}
                  isScanning={isScanning}
                  setIsScanning={setIsScanning}
                  setAiAnalysis={setAiAnalysis}
                  addTerminalLine={addTerminalLine}
                />
                <ActionButtons
                  scanData={scanData}
                  aiAnalysis={aiAnalysis}
                  isRunning={isRunning}
                  setIsRunning={setIsRunning}
                  addTerminalLine={addTerminalLine}
                />
                <Terminal lines={terminalLines} />
              </motion.div>
            ) : (
              <motion.div
                key="empty"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="flex-1 flex items-center justify-center"
              >
                <div className="text-center">
                  <div className="text-6xl mb-4 text-accent font-mono">{'>'}_</div>
                  <p className="text-muted text-sm">Select a project folder to get started</p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { FolderOpen, FolderCheck } from 'lucide-react';

export default function ProjectDropzone({ onFolderSelect, onFolderDrop, projectPath }) {
  const [isDragging, setIsDragging] = useState(false);

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragging(false);
    const items = Array.from(e.dataTransfer.items);
    for (const item of items) {
      const entry = item.webkitGetAsEntry?.();
      if (entry?.isDirectory) {
        const file = item.getAsFile();
        if (file?.path) onFolderDrop(file.path);
        return;
      }
    }
    const files = Array.from(e.dataTransfer.files);
    if (files[0]?.path) onFolderDrop(files[0].path);
  };

  return (
    <motion.button
      onClick={onFolderSelect}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={handleDrop}
      whileHover={{ scale: 1.01 }}
      whileTap={{ scale: 0.99 }}
      className={`
        w-full rounded-lg border-2 border-dashed p-6 text-center
        transition-all duration-200 cursor-pointer
        ${isDragging
          ? 'border-accent bg-accent/10 shadow-[0_0_20px_rgba(0,212,255,0.2)]'
          : projectPath
            ? 'border-success/50 bg-success/5'
            : 'border-border hover:border-accent/50 hover:bg-panel'
        }
      `}
    >
      {projectPath ? (
        <>
          <FolderCheck className="w-8 h-8 text-success mx-auto mb-2" />
          <p className="text-success text-xs font-mono truncate">
            {projectPath.split(/[\\/]/).pop()}
          </p>
          <p className="text-muted text-xs mt-1">Click to change</p>
        </>
      ) : (
        <>
          <FolderOpen className="w-8 h-8 text-muted mx-auto mb-2" />
          <p className="text-text text-sm font-medium">Drop project folder</p>
          <p className="text-muted text-xs mt-1">or click to browse</p>
        </>
      )}
    </motion.button>
  );
}

const TYPE_BADGES = {
  django: { color: 'text-green-400 bg-green-400/10 border-green-400/30', icon: '>' },
  flask: { color: 'text-blue-400 bg-blue-400/10 border-blue-400/30', icon: '~' },
  fastapi: { color: 'text-teal-400 bg-teal-400/10 border-teal-400/30', icon: '=' },
  streamlit: { color: 'text-pink-400 bg-pink-400/10 border-pink-400/30', icon: '*' },
  pytorch: { color: 'text-orange-400 bg-orange-400/10 border-orange-400/30', icon: '#' },
  tensorflow: { color: 'text-yellow-400 bg-yellow-400/10 border-yellow-400/30', icon: '@' },
  nodejs: { color: 'text-lime-400 bg-lime-400/10 border-lime-400/30', icon: '+' },
  react: { color: 'text-cyan-400 bg-cyan-400/10 border-cyan-400/30', icon: 'o' },
  nextjs: { color: 'text-white bg-white/10 border-white/30', icon: '^' },
  python: { color: 'text-blue-300 bg-blue-300/10 border-blue-300/30', icon: '>' },
  unknown: { color: 'text-muted bg-muted/10 border-muted/30', icon: '?' },
};

export default function ProjectInfo({ scanData, aiAnalysis }) {
  const type = aiAnalysis?.projectType || scanData?.projectType || 'unknown';
  const badge = TYPE_BADGES[type] || TYPE_BADGES.unknown;

  return (
    <div className="px-4 py-3 border-b border-border bg-surface flex items-center gap-4">
      <span className={`text-xs font-mono px-2 py-1 rounded border ${badge.color}`}>
        {badge.icon} {type.toUpperCase()}
      </span>
      <span className="text-xs text-muted font-mono truncate flex-1">
        {scanData?.folderPath}
      </span>
      <span className="text-xs text-muted font-mono">
        {scanData?.files?.length} files
      </span>
    </div>
  );
}

import { useEffect, useRef } from 'react';

const typeColors = {
  stdout: 'text-text',
  stderr: 'text-warning',
  exit: 'text-muted',
  info: 'text-accent',
  success: 'text-success',
  cmd: 'text-accent font-bold',
  warning: 'text-warning',
  muted: 'text-muted',
};

export default function Terminal({ lines }) {
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [lines]);

  return (
    <div className="flex-1 bg-void border-t border-border overflow-hidden flex flex-col">
      <div className="flex items-center gap-2 px-4 py-2 bg-surface border-b border-border">
        <div className="flex gap-1.5">
          <span className="w-2.5 h-2.5 rounded-full bg-danger/60" />
          <span className="w-2.5 h-2.5 rounded-full bg-warning/60" />
          <span className="w-2.5 h-2.5 rounded-full bg-success/60" />
        </div>
        <span className="text-muted text-xs font-mono ml-2">terminal output</span>
      </div>

      <div className="flex-1 overflow-y-auto p-4 font-mono text-xs leading-relaxed terminal-text">
        {lines.map((line, i) => (
          <span key={i} className={typeColors[line.type] || 'text-text'}>
            {line.text}
          </span>
        ))}
        <div ref={bottomRef} />
      </div>
    </div>
  );
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { Download, Play, Loader2 } from 'lucide-react';

export default function ActionButtons({ scanData, aiAnalysis, isRunning, setIsRunning, addTerminalLine }) {
  const [activeAction, setActiveAction] = useState(null);

  const canInstall = scanData?.requirementsFile;
  const canStart = scanData?.entryPoint || aiAnalysis?.startCommand;

  const runAction = async (type) => {
    if (isRunning) return;
    setIsRunning(true);
    setActiveAction(type);

    const cwd = scanData.folderPath;
    let command, args, label;

    if (type === 'install') {
      label = 'Installing requirements...';
      if (scanData.packageManager === 'npm') {
        command = 'npm'; args = ['install'];
      } else if (scanData.requirementsFile?.endsWith('pyproject.toml')) {
        command = 'pip'; args = ['install', '-e', '.'];
      } else {
        command = 'pip'; args = ['install', '-r', scanData.requirementsFile];
      }
    } else {
      label = 'Starting project...';
      const startCmd = aiAnalysis?.startCommand || detectStartCommand(scanData);
      [command, ...args] = startCmd.split(' ');
    }

    addTerminalLine({ type: 'info', text: `\n${label}\n` });
    addTerminalLine({ type: 'cmd', text: `$ ${command} ${args.join(' ')}\n` });

    window.electronAPI.onCommandOutput((data) => {
      addTerminalLine({ type: data.type, text: data.text });
    });

    await window.electronAPI.runCommand({ command, args, cwd });
    window.electronAPI.removeCommandListeners();

    setIsRunning(false);
    setActiveAction(null);
  };

  return (
    <div className="px-4 py-3 border-b border-border bg-panel flex gap-3">
      <ActionButton
        label="Install Requirements"
        icon={<Download className="w-4 h-4" />}
        onClick={() => runAction('install')}
        disabled={!canInstall || isRunning}
        loading={activeAction === 'install'}
        color="accent"
      />
      <ActionButton
        label="Start Project"
        icon={<Play className="w-4 h-4" />}
        onClick={() => runAction('start')}
        disabled={!canStart || isRunning}
        loading={activeAction === 'start'}
        color="success"
      />
    </div>
  );
}

function ActionButton({ label, icon, onClick, disabled, loading, color }) {
  const colors = {
    accent: 'border-accent/50 hover:border-accent hover:bg-accent/10 text-accent disabled:text-muted disabled:border-border',
    success: 'border-success/50 hover:border-success hover:bg-success/10 text-success disabled:text-muted disabled:border-border',
  };

  return (
    <motion.button
      onClick={onClick}
      disabled={disabled}
      whileHover={!disabled ? { scale: 1.02 } : {}}
      whileTap={!disabled ? { scale: 0.98 } : {}}
      className={`
        flex items-center gap-2 px-4 py-2 rounded-lg border text-sm font-mono
        transition-all duration-150 disabled:opacity-40 disabled:cursor-not-allowed
        ${colors[color]}
      `}
    >
      {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : icon}
      {label}
    </motion.button>
  );
}

function detectStartCommand(scanData) {
  if (!scanData.entryPoint) return 'echo "No entry point found"';
  const ep = scanData.entryPoint;
  if (ep.endsWith('.py')) return `python ${ep}`;
  if (ep === 'manage.py') return 'python manage.py runserver';
  if (ep.endsWith('.js')) return `node ${ep}`;
  return `python ${ep}`;
}

import { useEffect, useState } from 'react';
import { Brain } from 'lucide-react';

const AI_PROVIDERS = {
  openrouter: {
    baseURL: import.meta.env.VITE_OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1',
    apiKey: import.meta.env.VITE_OPENROUTER_API_KEY,
    model: import.meta.env.VITE_OPENROUTER_MODEL || 'google/gemini-flash-1.5',
  },
  gemini: {
    baseURL: 'https://generativelanguage.googleapis.com/v1beta/openai',
    apiKey: import.meta.env.VITE_GEMINI_API_KEY,
    model: import.meta.env.VITE_GEMINI_MODEL || 'gemini-1.5-flash',
  },
  nvidia: {
    baseURL: import.meta.env.VITE_NVIDIA_BASE_URL || 'https://integrate.api.nvidia.com/v1',
    apiKey: import.meta.env.VITE_NVIDIA_API_KEY,
    model: import.meta.env.VITE_NVIDIA_MODEL || 'meta/llama-3.1-8b-instruct',
  },
};

function getProvider() {
  if (import.meta.env.VITE_OPENROUTER_API_KEY) return AI_PROVIDERS.openrouter;
  if (import.meta.env.VITE_GEMINI_API_KEY) return AI_PROVIDERS.gemini;
  if (import.meta.env.VITE_NVIDIA_API_KEY) return AI_PROVIDERS.nvidia;
  return null;
}

export default function AIScanner({ scanData, isScanning, setIsScanning, setAiAnalysis, addTerminalLine }) {
  const [status, setStatus] = useState('idle');

  useEffect(() => {
    if (scanData && isScanning) {
      runAIScan();
    }
  }, [scanData]);

  const runAIScan = async () => {
    const provider = getProvider();

    if (!provider || !provider.apiKey) {
      setStatus('no-api');
      setIsScanning(false);
      addTerminalLine({ type: 'warning', text: 'No AI API key configured. Using file-based detection only.\n' });
      const fallback = heuristicAnalysis(scanData);
      setAiAnalysis(fallback);
      return;
    }

    setStatus('scanning');
    addTerminalLine({ type: 'info', text: `AI scanning project with ${provider.model}...\n` });

    try {
      const prompt = buildScanPrompt(scanData);

      const response = await fetch(`${provider.baseURL}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${provider.apiKey}`,
          'HTTP-Referer': 'projectlauncher-app',
        },
        body: JSON.stringify({
          model: provider.model,
          max_tokens: 800,
          response_format: { type: 'json_object' },
          messages: [
            {
              role: 'system',
              content: 'You are a project analysis AI. Respond ONLY with valid JSON. No markdown, no explanation.',
            },
            { role: 'user', content: prompt },
          ],
        }),
      });

      if (!response.ok) throw new Error(`API error: ${response.status}`);

      const data = await response.json();
      const text = data.choices?.[0]?.message?.content || '{}';
      const result = JSON.parse(text);

      setAiAnalysis(result);
      setStatus('done');
      addTerminalLine({ type: 'success', text: `AI analysis complete. Project type: ${result.projectType || 'unknown'}\n` });
      if (result.startCommand) {
        addTerminalLine({ type: 'info', text: `  Start command: ${result.startCommand}\n` });
      }
      if (result.description) {
        addTerminalLine({ type: 'muted', text: `  ${result.description}\n` });
      }

    } catch (err) {
      setStatus('error');
      addTerminalLine({ type: 'stderr', text: `AI scan failed: ${err.message}. Using heuristics.\n` });
      const fallback = heuristicAnalysis(scanData);
      setAiAnalysis(fallback);
    }

    setIsScanning(false);
  };

  const statusIcon = status === 'scanning' ? 'text-accent animate-pulse' :
    status === 'done' ? 'text-success' :
    status === 'error' || status === 'no-api' ? 'text-warning' : 'text-muted';

  const statusText = {
    idle: 'AI Scanner ready',
    scanning: 'Scanning project with AI...',
    done: 'AI Analysis complete',
    error: 'AI scan failed — using file detection',
    'no-api': 'No API key — using file detection',
  }[status];

  return (
    <div className="px-4 py-2 bg-panel border-b border-border flex items-center gap-3">
      <Brain className={`w-4 h-4 ${statusIcon}`} />
      <span className="text-xs font-mono text-muted">{statusText}</span>
    </div>
  );
}

function buildScanPrompt(scanData) {
  const files = scanData.files.slice(0, 40).join('\n');
  return `Analyze this project and respond with JSON only.

Project files:
${files}

Entry point detected: ${scanData.entryPoint || 'unknown'}
Requirements file: ${scanData.requirementsFile || 'none'}

Return JSON with these fields:
{
  "projectType": "django|flask|fastapi|streamlit|pytorch|tensorflow|nodejs|react|vue|unknown",
  "description": "one sentence description",
  "startCommand": "exact command to run the project",
  "installCommand": "exact command to install dependencies",
  "port": null or port number if applicable,
  "notes": "any important notes about running this project"
}`;
}

function heuristicAnalysis(scanData) {
  const files = scanData.files.map(f => f.toLowerCase());
  const has = (name) => files.some(f => f.includes(name));

  let projectType = 'unknown';
  let startCommand = null;

  if (has('manage.py')) { projectType = 'django'; startCommand = 'python manage.py runserver'; }
  else if (has('app.py') && has('flask')) { projectType = 'flask'; startCommand = 'python app.py'; }
  else if (has('streamlit')) { projectType = 'streamlit'; startCommand = `streamlit run ${scanData.entryPoint}`; }
  else if (has('main.py')) { projectType = 'python'; startCommand = 'python main.py'; }
  else if (has('package.json')) {
    projectType = 'nodejs';
    startCommand = has('next.config') ? 'npm run dev' : 'node index.js';
  }
  else if (has('uvicorn') || has('fastapi')) { projectType = 'fastapi'; startCommand = 'uvicorn main:app --reload'; }
  else if (has('gradio')) { projectType = 'gradio'; startCommand = 'python app.py'; }
  else if (has('next.config')) { projectType = 'nextjs'; startCommand = 'npm run dev'; }
  else if (has('vite.config')) { projectType = 'vite'; startCommand = 'npm run dev'; }

  return { projectType, startCommand, description: `${projectType} project`, notes: 'Detected via file analysis' };
}

