4	const AI_PROVIDERS = {
5	  openrouter: {
6	    baseURL: import.meta.env.VITE_OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1',
7	    apiKey: import.meta.env.VITE_OPENROUTER_API_KEY,
