23	  if (import.meta.env.VITE_OPENROUTER_API_KEY) return AI_PROVIDERS.openrouter;
24	  if (import.meta.env.VITE_GEMINI_API_KEY) return AI_PROVIDERS.gemini;
25	  if (import.meta.env.VITE_NVIDIA_API_KEY) return AI_PROVIDERS.nvidia;
26	  return null;
27	}
