29	export default function AIScanner({ scanData, isScanning, setIsScanning, setAiAnalysis, addTerminalLine }) {
30	  const [status, setStatus] = useState('idle');
31	
32	  useEffect(() => {
33	    if (scanData && isScanning) {
34	      runAIScan();
35	    }
36	  }, [scanData]);
37	
38	  const runAIScan = async () => {
39	    const provider = getProvider();
40	
41	    if (!provider || !provider.apiKey) {
42	      setStatus('no-api');
43	      setIsScanning(false);
44	      addTerminalLine({ type: 'warning', text: 'No AI API key configured. Using file-based detection only.\n' });
45	      const fallback = heuristicAnalysis(scanData);
46	      setAiAnalysis(fallback);
47	      return;
48	    }
49	
50	    setStatus('scanning');
51	    addTerminalLine({ type: 'info', text: `AI scanning project with ${provider.model}...\n` });
52	
53	    try {
54	      const prompt = buildScanPrompt(scanData);
55	
56	      const response = await fetch(`${provider.baseURL}/chat/completions`, {
57	        method: 'POST',
58	        headers: {
59	          'Content-Type': 'application/json',
60	          'Authorization': `Bearer ${provider.apiKey}`,
61	          'HTTP-Referer': 'projectlauncher-app',
62	        },
63	        body: JSON.stringify({
64	          model: provider.model,
65	          max_tokens: 800,
66	          messages: [
67	            {
68	              role: 'system',
69	              content: 'You are a project analysis AI. Respond ONLY with valid JSON. No markdown, no explanation.',
70	            },
71	            { role: 'user', content: prompt },
72	          ],
73	        }),
74	      });
75	
76	      if (!response.ok) throw new Error(`API error: ${response.status}`);
77	
78	      const data = await response.json();
79	      let text = data.choices?.[0]?.message?.content || '{}';
80	      // Extract JSON from markdown code blocks if present
81	      const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
82	      if (jsonMatch) text = jsonMatch[1].trim();
83	      const result = JSON.parse(text);
84	
85	      setAiAnalysis(result);
86	      setStatus('done');
87	      addTerminalLine({ type: 'success', text: `AI analysis complete. Project type: ${result.projectType || 'unknown'}\n` });
88	      if (result.startCommand) {
89	        addTerminalLine({ type: 'info', text: `  Start command: ${result.startCommand}\n` });
90	      }
91	      if (result.description) {
92	        addTerminalLine({ type: 'muted', text: `  ${result.description}\n` });
93	      }
94	
95	    } catch (err) {
96	      setStatus('error');
97	      addTerminalLine({ type: 'stderr', text: `AI scan failed: ${err.message}. Using heuristics.\n` });
98	      const fallback = heuristicAnalysis(scanData);
99	      setAiAnalysis(fallback);
100	    }
101	
102	    setIsScanning(false);
103	  };
104	
105	  const statusIcon = status === 'scanning' ? 'text-accent animate-pulse' :
106	    status === 'done' ? 'text-success' :
107	    status === 'error' || status === 'no-api' ? 'text-warning' : 'text-muted';
108	
109	  const statusText = {
110	    idle: 'AI Scanner ready',
111	    scanning: 'Scanning project with AI...',
112	    done: 'AI Analysis complete',
