import { useEffect, useState } from 'react';
import { Brain } from 'lucide-react';

const AI_PROVIDERS = {
  openrouter: {
    baseURL: import.meta.env.VITE_OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1',
    apiKey: import.meta.env.VITE_OPENROUTER_API_KEY,
    model: import.meta.env.VITE_OPENROUTER_MODEL || 'google/gemini-2.5-flash',
  },
  gemini: {
    baseURL: 'https://generativelanguage.googleapis.com/v1beta/openai',
    apiKey: import.meta.env.VITE_GEMINI_API_KEY,
    model: import.meta.env.VITE_GEMINI_MODEL || 'gemini-1.5-flash',
  },
  nvidia: {
    baseURL: import.meta.env.VITE_NVIDIA_BASE_URL || 'https://integrate.api.nvidia.com/v1',
    apiKey: import.meta.env.VITE_NVIDIA_API_KEY,
    model: import.meta.env.VITE_NVIDIA_MODEL || 'meta/llama-3.1-8b-instruct',
  },
};

function getProvider() {
  if (import.meta.env.VITE_OPENROUTER_API_KEY) return AI_PROVIDERS.openrouter;
  if (import.meta.env.VITE_GEMINI_API_KEY) return AI_PROVIDERS.gemini;
  if (import.meta.env.VITE_NVIDIA_API_KEY) return AI_PROVIDERS.nvidia;
  return null;
}

export default function AIScanner({ scanData, isScanning, setIsScanning, setAiAnalysis, addTerminalLine }) {
  const [status, setStatus] = useState('idle');

  useEffect(() => {
    if (scanData && isScanning) {
      runAIScan();
    }
  }, [scanData]);

  const runAIScan = async () => {
    const provider = getProvider();

    if (!provider || !provider.apiKey) {
      setStatus('no-api');
      setIsScanning(false);
      addTerminalLine({ type: 'warning', text: 'No AI API key configured. Using file-based detection only.\n' });
      const fallback = heuristicAnalysis(scanData);
      setAiAnalysis(fallback);
      return;
    }

    setStatus('scanning');
    addTerminalLine({ type: 'info', text: `AI scanning project with ${provider.model}...\n` });

    try {
      const prompt = buildScanPrompt(scanData);

      const response = await fetch(`${provider.baseURL}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${provider.apiKey}`,
          'HTTP-Referer': 'projectlauncher-app',
        },
        body: JSON.stringify({
          model: provider.model,
          max_tokens: 800,
          messages: [
            {
              role: 'system',
              content: 'You are a project analysis AI. Respond ONLY with valid JSON. No markdown, no explanation.',
            },
            { role: 'user', content: prompt },
          ],
        }),
      });

      if (!response.ok) throw new Error(`API error: ${response.status}`);

      const data = await response.json();
      let text = data.choices?.[0]?.message?.content || '{}';
      // Extract JSON from markdown code blocks if present
      const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (jsonMatch) text = jsonMatch[1].trim();
      const result = JSON.parse(text);

      setAiAnalysis(result);
      setStatus('done');
      addTerminalLine({ type: 'success', text: `AI analysis complete. Project type: ${result.projectType || 'unknown'}\n` });
      if (result.startCommand) {
        addTerminalLine({ type: 'info', text: `  Start command: ${result.startCommand}\n` });
      }
      if (result.description) {
        addTerminalLine({ type: 'muted', text: `  ${result.description}\n` });
      }

    } catch (err) {
      setStatus('error');
      addTerminalLine({ type: 'stderr', text: `AI scan failed: ${err.message}. Using heuristics.\n` });
      const fallback = heuristicAnalysis(scanData);
      setAiAnalysis(fallback);
    }

    setIsScanning(false);
  };

  const statusIcon = status === 'scanning' ? 'text-accent animate-pulse' :
    status === 'done' ? 'text-success' :
    status === 'error' || status === 'no-api' ? 'text-warning' : 'text-muted';

  const statusText = {
    idle: 'AI Scanner ready',
    scanning: 'Scanning project with AI...',
    done: 'AI Analysis complete',
    error: 'AI scan failed — using file detection',
    'no-api': 'No API key — using file detection',
  }[status];

  return (
    <div className="px-4 py-2 bg-panel border-b border-border flex items-center gap-3">
      <Brain className={`w-4 h-4 ${statusIcon}`} />
      <span className="text-xs font-mono text-muted">{statusText}</span>
    </div>
  );
}

function buildScanPrompt(scanData) {
  const files = scanData.files.slice(0, 40).join('\n');
  return `Analyze this project and respond with JSON only.

Project files:
${files}

Entry point detected: ${scanData.entryPoint || 'unknown'}
Requirements file: ${scanData.requirementsFile || 'none'}

Return JSON with these fields:
{
  "projectType": "django|flask|fastapi|streamlit|pytorch|tensorflow|nodejs|react|vue|unknown",
  "description": "one sentence description",
  "startCommand": "exact command to run the project",
  "installCommand": "exact command to install dependencies",
  "port": null or port number if applicable,
  "notes": "any important notes about running this project"
}`;
}

function heuristicAnalysis(scanData) {
  const files = scanData.files.map(f => f.toLowerCase());
  const has = (name) => files.some(f => f.includes(name));

  let projectType = 'unknown';
  let startCommand = null;

  if (has('manage.py')) { projectType = 'django'; startCommand = 'python manage.py runserver'; }
  else if (has('app.py') && has('flask')) { projectType = 'flask'; startCommand = 'python app.py'; }
  else if (has('streamlit')) { projectType = 'streamlit'; startCommand = `streamlit run ${scanData.entryPoint}`; }
  else if (has('main.py')) { projectType = 'python'; startCommand = 'python main.py'; }
  else if (has('package.json')) {
    projectType = 'nodejs';
    startCommand = has('next.config') ? 'npm run dev' : 'node index.js';
  }
  else if (has('uvicorn') || has('fastapi')) { projectType = 'fastapi'; startCommand = 'uvicorn main:app --reload'; }
  else if (has('gradio')) { projectType = 'gradio'; startCommand = 'python app.py'; }
  else if (has('next.config')) { projectType = 'nextjs'; startCommand = 'npm run dev'; }
  else if (has('vite.config')) { projectType = 'vite'; startCommand = 'npm run dev'; }

  return { projectType, startCommand, description: `${projectType} project`, notes: 'Detected via file analysis' };
}

