  function scanDir(dir, depth = 0) {
    if (depth > 5) return;
    try {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        if (entry.name.startsWith('.') || skipDirs.has(entry.name)) continue;

        const fullPath = path.join(dir, entry.name);
        const relPath = path.relative(folderPath, fullPath);

        if (entry.isFile()) {
          result.files.push(relPath);

          // Requirements detection
          for (const [name, pm] of reqFiles) {
            if (entry.name === name && !result.requirementsFile) {
              result.requirementsFile = relPath;
              result.packageManager = result.packageManager || pm;
            }
          }

          // ROS2 launch files
          if (entry.name.endsWith('.launch.py') || entry.name.endsWith('.launch.xml')) {
            result.launchFiles.push(relPath);
          }

          // Zephyr config
          if (entry.name === 'prj.conf' && !result.buildSystem) {
            result.buildSystem = 'west';
          }

          // Entry point detection
          for (const ep of entryPriority) {
            if (entry.name === ep.name && !result.entryPoint) {
              result.entryPoint = relPath;
              result.projectType = result.projectType || ep.type;
            }
          }
        } else if (entry.isDirectory()) {
          // Detect additional project markers
          if (entry.name === 'launch' && !result.buildSystem) {
            result.buildSystem = result.buildSystem || 'colcon';
          }
          scanDir(fullPath, depth + 1);
        }
      }
    } catch (e) { /* skip permission errors */ }
  }

  scanDir(folderPath);

  // Post-scan type refinement
  const fileNames = result.files.map(f => f.replace(/\\/g, '/').split('/').pop().toLowerCase());

  if (fileNames.includes('package.xml') && fileNames.includes('cmakelists.txt')) {
    result.projectType = result.projectType || 'ros2-robotics';
    result.buildSystem = 'colcon';
  }
  if (fileNames.includes('prj.conf') && fileNames.includes('cmakelists.txt')) {
    result.projectType = result.projectType || 'zephyr-rtos';
    result.buildSystem = 'west';
  }
  if (fileNames.includes('mission_test.py') || fileNames.includes('preflight_check.py')) {
    result.projectType = 'px4-uav';
  }
  if (fileNames.includes('drone_arm_fea.py') || fileNames.includes('cfd_report.py')) {
    result.projectType = 'fem-cfd';
  }

  return result;
});

