};

export default function ProjectInfo({ scanData, aiAnalysis }) {
  const type = aiAnalysis?.projectType || scanData?.projectType || 'unknown';
  const badge = TYPE_BADGES[type] || TYPE_BADGES.unknown;
  const buildLabel = scanData?.buildSystem
    ? ` · ${scanData.buildSystem.toUpperCase()}`
    : '';
  const pkgLabel = scanData?.packageManager
    ? ` · ${scanData.packageManager}`
    : '';

  return (
    <div className="px-4 py-3 border-b border-border bg-surface flex items-center gap-4">
      <span className={`text-xs font-mono px-2 py-1 rounded border ${badge.color}`}>
        {badge.icon} {type.toUpperCase()}
      </span>
      <span className="text-xs text-muted font-mono truncate flex-1">
        {scanData?.folderPath}
      </span>
      <span className="text-xs text-muted font-mono">
        {scanData?.files?.length} files{buildLabel}{pkgLabel}
      </span>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Brain } from 'lucide-react';

const AI_PROVIDERS = {
  openrouter: {
    baseURL: import.meta.env.VITE_OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1',
    apiKey: import.meta.env.VITE_OPENROUTER_API_KEY,
    model: import.meta.env.VITE_OPENROUTER_MODEL || 'google/gemini-2.5-flash',
  },
  gemini: {
    baseURL: 'https://generativelanguage.googleapis.com/v1beta/openai',
    apiKey: import.meta.env.VITE_GEMINI_API_KEY,
    model: import.meta.env.VITE_GEMINI_MODEL || 'gemini-1.5-flash',
  },
  nvidia: {
    baseURL: import.meta.env.VITE_NVIDIA_BASE_URL || 'https://integrate.api.nvidia.com/v1',
    apiKey: import.meta.env.VITE_NVIDIA_API_KEY,
    model: import.meta.env.VITE_NVIDIA_MODEL || 'meta/llama-3.1-8b-instruct',
  },
};

function getProvider() {
  if (import.meta.env.VITE_OPENROUTER_API_KEY) return AI_PROVIDERS.openrouter;
  if (import.meta.env.VITE_GEMINI_API_KEY) return AI_PROVIDERS.gemini;
  if (import.meta.env.VITE_NVIDIA_API_KEY) return AI_PROVIDERS.nvidia;
  return null;
}

const PROJECT_TYPES = [
  'django', 'flask', 'fastapi', 'streamlit', 'pytorch', 'tensorflow',
  'nodejs', 'react', 'vue', 'nextjs', 'vite',
  'ros2-robotics', 'px4-uav', 'zephyr-rtos', 'fem-cfd',
  'rust-cargo', 'gradio', 'python', 'unknown',
];

export default function AIScanner({ scanData, isScanning, setIsScanning, setAiAnalysis, addTerminalLine }) {
  const [status, setStatus] = useState('idle');

  useEffect(() => {
    if (scanData && isScanning) {
      runAIScan();
    }
  }, [scanData]);

  const runAIScan = async () => {
    const provider = getProvider();

    if (!provider || !provider.apiKey) {
      setStatus('no-api');
      setIsScanning(false);
      addTerminalLine({ type: 'warning', text: 'No AI API key configured. Using file-based detection only.\n' });
      setAiAnalysis(heuristicAnalysis(scanData));
      return;
    }

    setStatus('scanning');
    addTerminalLine({ type: 'info', text: `AI scanning project with ${provider.model}...\n` });

    try {
      const prompt = buildScanPrompt(scanData);

      const response = await fetch(`${provider.baseURL}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${provider.apiKey}`,
          'HTTP-Referer': 'projectlauncher-app',
        },
        body: JSON.stringify({
          model: provider.model,
          max_tokens: 800,
          messages: [
            {
              role: 'system',
              content: `You are a project analysis AI for an industrial-grade engineering tool. Respond ONLY with valid JSON. No markdown, no explanation.\n\nYou analyze software projects across: web (Django/Flask/FastAPI/React/Next/Vite), robotics (ROS2/MoveIt2/Nav2), drones (PX4/MAVSDK/Gazebo), embedded (Zephyr RTOS/STM32/FreeRTOS), simulation (FEniCSx/OpenFOAM), and general Python/Node/Rust.`,
            },
            { role: 'user', content: prompt },
          ],
        }),
      });

      if (!response.ok) throw new Error(`API error: ${response.status}`);

      const data = await response.json();
      let text = data.choices?.[0]?.message?.content || '{}';
      const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (jsonMatch) text = jsonMatch[1].trim();
      const result = JSON.parse(text);

      // Validate projectType against known types
      if (!PROJECT_TYPES.includes(result.projectType)) {
        result.projectType = heuristicAnalysis(scanData).projectType;
      }

      setAiAnalysis(result);
      setStatus('done');
      addTerminalLine({ type: 'success', text: `AI analysis complete. Project type: ${result.projectType || 'unknown'}\n` });
      if (result.startCommand) {
        addTerminalLine({ type: 'info', text: `  Start command: ${result.startCommand}\n` });
      }
      if (result.description) {
        addTerminalLine({ type: 'muted', text: `  ${result.description}\n` });
      }

    } catch (err) {
      setStatus('error');
      addTerminalLine({ type: 'stderr', text: `AI scan failed: ${err.message}. Using heuristics.\n` });
      setAiAnalysis(heuristicAnalysis(scanData));
    }

    setIsScanning(false);
  };

  const statusIcon = status === 'scanning' ? 'text-accent animate-pulse' :
    status === 'done' ? 'text-success' :
    status === 'error' || status === 'no-api' ? 'text-warning' : 'text-muted';

  const statusText = {
    idle: 'AI Scanner ready',
    scanning: 'Scanning project with AI...',
    done: 'AI Analysis complete',
    error: 'AI scan failed — using file detection',
    'no-api': 'No API key — using file detection',
  }[status];

  return (
    <div className="px-4 py-2 bg-panel border-b border-border flex items-center gap-3">
      <Brain className={`w-4 h-4 ${statusIcon}`} />
      <span className="text-xs font-mono text-muted">{statusText}</span>
    </div>
  );
}

function buildScanPrompt(scanData) {
  const files = scanData.files.slice(0, 40).join('\n');
  const launchInfo = scanData.launchFiles?.length
    ? `\nROS2 launch files: ${scanData.launchFiles.join(', ')}`
    : '';
  return `Analyze this project and respond with JSON only.

Project files:
${files}${launchInfo}

Entry point: ${scanData.entryPoint || 'unknown'}
Requirements: ${scanData.requirementsFile || 'none'}
Build system: ${scanData.buildSystem || 'unknown'}
Package manager: ${scanData.packageManager || 'unknown'}

Return JSON with these fields:
{
  "projectType": "${PROJECT_TYPES.join('|')}",
  "description": "one sentence description of what this project does",
  "startCommand": "exact command to run/build/deploy this project",
  "installCommand": "exact command to install all dependencies",
  "buildCommand": "exact command to build/compile (if applicable)",
  "port": null or port number if this is a server/web app,
  "hardwareTarget": null or "stm32f4"|"pixhawk"|"raspberry-pi"|"qemu" if embedded,
  "notes": "any important notes about running or deploying this project"
}`;
}

function heuristicAnalysis(scanData) {
  const files = scanData.files.map(f => f.toLowerCase());
  const fileNames = files.map(f => f.replace(/\\/g, '/').split('/').pop());
  const has = (name) => fileNames.some(f => f === name.toLowerCase());
  const hasGlob = (name) => files.some(f => f.includes(name.toLowerCase()));
  const allNames = fileNames.join(' ');

  let projectType = 'unknown';
  let startCommand = null;
  let installCommand = null;
  let buildCommand = null;
  const ep = scanData.entryPoint || '';

  // ── ROS2 Robotics ──────────────────────────────────────────────────────────
  if (has('package.xml') && has('cmakelists.txt')) {
    projectType = 'ros2-robotics';
    const launchFile = scanData.launchFiles?.[0] || '';
    const pkg = launchFile ? launchFile.replace(/\\/g, '/').split('/')[0] : 'my_pkg';
    installCommand = 'colcon build --symlink-install';
    buildCommand = 'colcon build';
    startCommand = launchFile
      ? `ros2 launch ${launchFile.replace('.launch.py','').replace('.launch.xml','')}`
      : `ros2 run ${pkg} ${ep.replace('.py','')}`;
  }

  // ── PX4 UAV ───────────────────────────────────────────────────────────────
  else if (has('mission_test.py') || hasGlob('px4') || hasGlob('mavsdk')) {
    projectType = 'px4-uav';
    installCommand = 'pip install mavsdk asyncio pyulog';
    startCommand = ep.endsWith('.py') ? `python ${ep}` : 'make px4_sitl gz_x500';
  }

  // ── Zephyr RTOS ────────────────────────────────────────────────────────────
  else if (has('prj.conf') || hasGlob('zephyr') || hasGlob('west.yml')) {
    projectType = 'zephyr-rtos';
    installCommand = 'pip install west pyserial && west update';
    buildCommand = 'west build -b qemu_cortex_m3 .';
    startCommand = 'west build -b qemu_cortex_m3 . && west build -t run';
  }

  // ── FEM / CFD ──────────────────────────────────────────────────────────────
  else if (has('drone_arm_fea.py') || has('cfd_report.py') || hasGlob('fenics') || hasGlob('openfoam') || hasGlob('dolfinx')) {
    projectType = 'fem-cfd';
    installCommand = 'pip install fenics-dolfinx gmsh meshio pyvista matplotlib';
    startCommand = ep.endsWith('.py') ? `python ${ep}` : 'python drone_arm_fea.py';
  }

  // ── Rust / Cargo ───────────────────────────────────────────────────────────
  else if (has('cargo.toml')) {
    projectType = 'rust-cargo';
    installCommand = 'cargo build';
    buildCommand = 'cargo build --release';
    startCommand = 'cargo run';
  }

  // ── Web / Python ───────────────────────────────────────────────────────────
  else if (has('manage.py')) {
    projectType = 'django';
    startCommand = 'python manage.py runserver';
    installCommand = 'pip install -r requirements.txt';
  }
  else if (has('app.py') && hasGlob('flask')) {
    projectType = 'flask';
    startCommand = 'python app.py';
    installCommand = 'pip install -r requirements.txt';
  }
  else if (hasGlob('streamlit')) {
    projectType = 'streamlit';
    startCommand = `streamlit run ${ep || 'app.py'}`;
    installCommand = 'pip install -r requirements.txt';
  }
  else if (hasGlob('uvicorn') || hasGlob('fastapi')) {
    projectType = 'fastapi';
    startCommand = 'uvicorn main:app --reload';
    installCommand = 'pip install -r requirements.txt';
  }
  else if (hasGlob('gradio')) {
    projectType = 'gradio';
    startCommand = `python ${ep || 'app.py'}`;
    installCommand = 'pip install -r requirements.txt';
  }
  else if (has('main.py')) {
    projectType = 'python';
    startCommand = 'python main.py';
    installCommand = 'pip install -r requirements.txt';
  }
  else if (has('app.py')) {
    projectType = 'python';
    startCommand = 'python app.py';
    installCommand = 'pip install -r requirements.txt';
  }

  // ── Web / Node ─────────────────────────────────────────────────────────────
  else if (has('package.json')) {
    if (hasGlob('next.config')) {
      projectType = 'nextjs';
      startCommand = 'npm run dev';
    } else if (hasGlob('vite.config')) {
      projectType = 'vite';
      startCommand = 'npm run dev';
    } else if (hasGlob('react')) {
      projectType = 'react';
      startCommand = 'npm start';
    } else {
      projectType = 'nodejs';
      startCommand = ep.endsWith('.js') ? `node ${ep}` : 'npm start';
    }
    installCommand = 'npm install';
  }

  // ── Generic fallback ───────────────────────────────────────────────────────
  else if (ep) {
    projectType = ep.endsWith('.py') ? 'python' : ep.endsWith('.c') ? 'zephyr-rtos' : 'unknown';
    startCommand = ep.endsWith('.py') ? `python ${ep}` : ep.endsWith('.c') ? 'west build -t run' : `python ${ep}`;
    installCommand = 'pip install -r requirements.txt';
  }

  return {
    projectType,
    description: `${projectType.replace(/-/g, ' ').toUpperCase()} project`,
    startCommand: startCommand || `python ${ep || 'main.py'}`,
    installCommand: installCommand || 'pip install -r requirements.txt',
    buildCommand,
    notes: 'Detected via industrial heuristic analysis',
  };
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { Download, Play, Loader2, Hammer, StopCircle } from 'lucide-react';

export default function ActionButtons({ scanData, aiAnalysis, isRunning, setIsRunning, addTerminalLine }) {
  const [activeAction, setActiveAction] = useState(null);

  const canInstall = scanData?.requirementsFile || aiAnalysis?.installCommand;
  const canBuild = scanData?.buildSystem || aiAnalysis?.buildCommand;
  const canStart = scanData?.entryPoint || aiAnalysis?.startCommand;

  const runAction = async (type) => {
    if (isRunning) return;
    setIsRunning(true);
    setActiveAction(type);

    const cwd = scanData.folderPath;
    let command, args;

    if (type === 'install') {
      command = resolveInstallCommand(scanData, aiAnalysis);
    } else if (type === 'build') {
      command = aiAnalysis?.buildCommand || resolveBuildCommand(scanData);
    } else {
      command = aiAnalysis?.startCommand || resolveStartCommand(scanData);
    }

    const label = {
      install: 'Installing dependencies...',
      build: 'Building project...',
      start: 'Starting project...',
    }[type];

    const parts = command.split(/\s+/);
    command = parts[0];
    args = parts.slice(1).filter(Boolean);

    addTerminalLine({ type: 'info', text: `\n${label}\n` });
    addTerminalLine({ type: 'cmd', text: `[${cwd}]$ ${command} ${args.join(' ')}\n` });

    window.electronAPI.onCommandOutput((data) => {
      addTerminalLine({ type: data.type, text: data.text });
    });

    await window.electronAPI.runCommand({ command, args, cwd });
    window.electronAPI.removeCommandListeners();

    setIsRunning(false);
    setActiveAction(null);
  };

  return (
    <div className="px-4 py-3 border-b border-border bg-panel flex gap-3 flex-wrap">
      <ActionButton
        label="Install Requirements"
        icon={<Download className="w-4 h-4" />}
        onClick={() => runAction('install')}
        disabled={!canInstall || isRunning}
        loading={activeAction === 'install'}
        color="accent"
      />
      {canBuild && (
        <ActionButton
          label="Build"
          icon={<Hammer className="w-4 h-4" />}
          onClick={() => runAction('build')}
          disabled={isRunning}
          loading={activeAction === 'build'}
          color="warning"
        />
      )}
      <ActionButton
        label="Start Project"
        icon={<Play className="w-4 h-4" />}
        onClick={() => runAction('start')}
        disabled={!canStart || isRunning}
        loading={activeAction === 'start'}
        color="success"
      />
    </div>
  );
}

function ActionButton({ label, icon, onClick, disabled, loading, color }) {
  const colors = {
    accent: 'border-accent/50 hover:border-accent hover:bg-accent/10 text-accent disabled:text-muted disabled:border-border',
    success: 'border-success/50 hover:border-success hover:bg-success/10 text-success disabled:text-muted disabled:border-border',
    warning: 'border-warning/50 hover:border-warning hover:bg-warning/10 text-warning disabled:text-muted disabled:border-border',
  };

  return (
    <motion.button
      onClick={onClick}
      disabled={disabled}
      whileHover={!disabled ? { scale: 1.02 } : {}}
      whileTap={!disabled ? { scale: 0.98 } : {}}
      className={`
        flex items-center gap-2 px-4 py-2 rounded-lg border text-sm font-mono
        transition-all duration-150 disabled:opacity-40 disabled:cursor-not-allowed
        ${colors[color]}
      `}
    >
      {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : icon}
      {label}
    </motion.button>
  );
}

// ── Command Resolution ─────────────────────────────────────────────────────────

function resolveInstallCommand(scanData, aiAnalysis) {
  const pm = scanData.packageManager;
  const rf = scanData.requirementsFile || '';

  if (aiAnalysis?.installCommand) return aiAnalysis.installCommand;

  // Industrial package managers
  if (pm === 'cargo') return 'cargo build';
  if (pm === 'poetry') return 'poetry install';
  if (pm === 'pipenv') return 'pipenv install';
  if (pm === 'yarn') return 'yarn install';
  if (pm === 'cmake') return 'mkdir -p build && cd build && cmake .. && make -j$(nproc)';
  if (pm === 'colcon') return 'colcon build --symlink-install';
  if (pm === 'conan') return 'conan install . --build=missing';
  if (pm === 'npm') return 'npm install';

  // Standard pip
  if (rf.endsWith('pyproject.toml')) return 'pip install -e .';
  if (rf.endsWith('Pipfile')) return 'pipenv install';
  return `pip install -r ${rf || 'requirements.txt'}`;
}

function resolveBuildCommand(scanData) {
  const bs = scanData.buildSystem;
  if (bs === 'west') return 'west build -b qemu_cortex_m3 .';
  if (bs === 'colcon') return 'colcon build --symlink-install';
  if (bs === 'cargo') return 'cargo build --release';
  return 'make';
}

function resolveStartCommand(scanData) {
  if (!scanData.entryPoint) return 'echo "No entry point detected"';
  const ep = scanData.entryPoint;
  const pt = scanData.projectType;

  // Industrial start commands
  if (pt === 'ros2-robotics') {
    if (scanData.launchFiles?.length) {
      const lf = scanData.launchFiles[0].replace(/\\/g, '/');
      return `ros2 launch ${lf.replace('.launch.py', '').replace('.launch.xml', '')}`;
    }
    return `ros2 run my_pkg ${ep.replace('.py', '')}`;
  }
  if (pt === 'zephyr-rtos') return 'west build -b qemu_cortex_m3 . && west build -t run';
  if (pt === 'px4-uav') return ep.endsWith('.py') ? `python ${ep}` : 'make px4_sitl gz_x500';
  if (pt === 'fem-cfd') return `python ${ep}`;
  if (pt === 'rust-cargo') return 'cargo run';
  if (pt === 'django') return 'python manage.py runserver';

  // Standard start commands
  if (ep.endsWith('.py')) return `python ${ep}`;
  if (ep.endsWith('.js')) return `node ${ep}`;
  if (ep.endsWith('.c')) return 'west build -t run';
  return `python ${ep}`;
}

import { useEffect, useRef } from 'react';

const typeColors = {
  stdout: 'text-text',
  stderr: 'text-warning',
  exit: 'text-muted',
  info: 'text-accent',
  success: 'text-success',
  cmd: 'text-accent font-bold',
  warning: 'text-warning',
  muted: 'text-muted',
  // ── ROS2 log levels ──────────────────────────────────────────────────────
  ros2_info: 'text-accent',
  ros2_warn: 'text-warning',
  ros2_error: 'text-danger',
  ros2_debug: 'text-muted',
  // ── MAVLink / PX4 ────────────────────────────────────────────────────────
  mavlink: 'text-amber-400',
  px4_info: 'text-amber-300',
  // ── FEM / Solver convergence ──────────────────────────────────────────────
  solver_iter: 'text-muted',
  solver_conv: 'text-success font-bold',
  solver_div: 'text-danger font-bold',
  // ── Build systems ─────────────────────────────────────────────────────────
  cargo: 'text-orange-400',
  cmake: 'text-teal-400',
  colcon: 'text-emerald-400',
  west: 'text-indigo-400',
};

// Regex patterns for domain-specific log classification
const LOG_PATTERNS = [
  // ROS2 log levels
  { re: /\[INFO\]|\[INFO /i, type: 'ros2_info' },
  { re: /\[WARN\]|\[WARN /i, type: 'ros2_warn' },
  { re: /\[ERROR\]|\[ERROR /i, type: 'ros2_error' },
  { re: /\[DEBUG\]|\[DEBUG /i, type: 'ros2_debug' },
  // MAVLink / PX4
  { re: /MAVLink|MAV_|mavlink|PX4/i, type: 'mavlink' },
  { re: /ARMED|DISARMED|PREFLIGHT|MISSION/i, type: 'px4_info' },
  // Solver convergence
  { re: /converged|Convergence|residual.*[<]\s*1e/i, type: 'solver_conv' },
  { re: /diverged|DIVERGED|NaN|inf/i, type: 'solver_div' },
  { re: /Time\s*=|Iteration|iter\s/i, type: 'solver_iter' },
  // Build systems
  { re: /\bCompiling\b|Running\s+`rustc/i, type: 'cargo' },
  { re: /cmake|Building\s+CXX|Building\s+C\b/i, type: 'cmake' },
  { re: /\[Processing|colcon/i, type: 'colcon' },
  { re: /west\s|ninja:|zephyr/i, type: 'west' },
];

function classifyLine(text) {
  for (const { re, type } of LOG_PATTERNS) {
    if (re.test(text)) return type;
  }
  return null;
}

export default function Terminal({ lines }) {
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [lines]);

  return (
    <div className="flex-1 bg-void border-t border-border overflow-hidden flex flex-col">
      <div className="flex items-center gap-2 px-4 py-2 bg-surface border-b border-border">
        <div className="flex gap-1.5">
          <span className="w-2.5 h-2.5 rounded-full bg-danger/60" />
          <span className="w-2.5 h-2.5 rounded-full bg-warning/60" />
          <span className="w-2.5 h-2.5 rounded-full bg-success/60" />
        </div>
        <span className="text-muted text-xs font-mono ml-2">terminal output</span>
        <span className="flex-1" />
        <span className="text-muted text-[10px] font-mono">ROS2 · PX4 · Zephyr · FEM</span>
      </div>

      <div className="flex-1 overflow-y-auto p-4 font-mono text-xs leading-relaxed terminal-text">
        {lines.map((line, i) => {
          const domainType = classifyLine(line.text || '');
          const effectiveType = domainType || line.type;
          return (
            <span key={i} className={typeColors[effectiveType] || 'text-text'}>
              {line.text}
            </span>
          );
        })}
        <div ref={bottomRef} />
      </div>
    </div>
  );
}

